#include<bits/stdc++.h>
using namespace std;
struct Node {
    char left,right;
};
map<char,Node>t;
void pre_order(char x){
	cout<<x;
	if(t[x].left!='*')pre_order(t[x].left);
	if(t[x].right!='*')pre_order(t[x].right);
}
int main(void){
    int n;char x,y;
    cin>>n;
    cin>>y;
    cin>>t[y].left>>t[y].right;
    for(int i=2;i<=n;i++){
    	cin>>x;
		cin>>t[x].left>>t[x].right;
	}
    pre_order(y);
    return false;
}
